const items = $input.all();
const html = items[0].json.data || items[0].json.body || '';

if (!html || typeof html !== 'string') {
  return [{ json: { websiteText: '', websiteScraped: false } }];
}

// Strip script and style tags with their content
let text = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '')
  .replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '')
  .replace(/<header[^>]*>[\s\S]*?<\/header>/gi, '');

// Strip all HTML tags
text = text.replace(/<[^>]+>/g, ' ');

// Decode common HTML entities
text = text
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'")
  .replace(/&nbsp;/g, ' ');

// Clean up whitespace
text = text
  .replace(/\s+/g, ' ')
  .replace(/\n\s*\n/g, '\n')
  .trim();

// Truncate to ~8000 chars to avoid overwhelming the AI prompt
if (text.length > 8000) {
  text = text.substring(0, 8000) + '\n[...truncated]';
}

return [{ json: { websiteText: text, websiteScraped: true } }];

